// `HostState::next_ensures` is an open spec fn that's a conjunction of six clauses:
//   1) ok == new_netc.ok()
//   2) ok ==> new_self.invariants(&new_netc.my_end_point())
//   3) ok ==> HostState::next(old_self.view(), new_self.view(), res@.ios)
//   4) ok ==> res@.event_seq() == res@.ios
//   5) (ok || res@.sends.len()>0) ==> new_netc.history() == old_netc.history() + res@.event_seq()
//   6) res@.well_typed_events()
// Re-reveal the closed spec fns invoked by clause 2/3 so the trigger search can see inside them
// on both r1 and r2.
reveal(HostState::view);
reveal(HostState::invariants);

// Surface each conjunct of next_ensures as a tautological implication for both runs
// (P ∧ C ==> C is a tautology, so each assert is sound regardless of whether the ensures
// actually holds for that triple).  This pre-pays the trigger instantiation that z3
// otherwise has to discover on its own.

// Clause 1: ok == new_netc.ok()
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> r1.0 == post1_netc.ok());
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> r2.0 == post2_netc.ok());

// Clause 2: ok ==> new_self.invariants(...)
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (r1.0 ==> post1_self_.invariants(&post1_netc.my_end_point())));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (r2.0 ==> post2_self_.invariants(&post2_netc.my_end_point())));

// Clause 3: ok ==> HostState::next(pre@, post@, res@.ios)
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (r1.0 ==> HostState::next(pre_self_@, post1_self_@, (r1.1)@.ios)));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (r2.0 ==> HostState::next(pre_self_@, post2_self_@, (r2.1)@.ios)));

// Clause 4: ok ==> event_seq() == ios
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (r1.0 ==> (r1.1)@.event_seq() == (r1.1)@.ios));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (r2.0 ==> (r2.1)@.event_seq() == (r2.1)@.ios));

// Clause 5: history extension
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> ((r1.0 || (r1.1)@.sends.len() > 0)
         ==> post1_netc.history() == pre_netc.history() + (r1.1)@.event_seq()));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> ((r2.0 || (r2.1)@.sends.len() > 0)
         ==> post2_netc.history() == pre_netc.history() + (r2.1)@.event_seq()));

// Clause 6: well_typed_events
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (r1.1)@.well_typed_events());
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (r2.1)@.well_typed_events());

// EventResults.view() is the EventResultsView { recvs, clocks, sends, ios }, so equality of
// the views reduces to component-wise equality.  Surface that decomposition as a tautology
// so z3 can derive `r1.1@.view() == r2.1@.view()` from the four component equalities (if
// it can establish them) without needing to reason about the view function itself.
assert(forall|x: EventResults, y: EventResults|
    x.recvs == y.recvs && x.clocks == y.clocks && x.sends == y.sends && x.ios == y.ios
    ==> #[trigger] x.view() == #[trigger] y.view());
